Include %occStatus

Class Catalog.ItemSearch Extends %RegisteredObject
{

    /// Search items by category, returning only active records
    ClassMethod SearchItems(category As %String) As %ListOfDataTypes
    {
        Set results = ##class(%ListOfDataTypes).%New()
        Set stmt = ##class(%SQL.Statement).%New()
        // BUGGY: Missing filter to exclude expired items
        Set sc = stmt.%Prepare("SELECT Name FROM Catalog_Item WHERE Category = ?")
        Set rs = stmt.%Execute(category)
        While rs.%Next() {
            Do results.Insert(rs.%Get("Name"))
        }
        Return results
    }

}

Class Catalog.Item Extends %Persistent
{

    Property Name As %String;
    Property Category As %String;
    /// NULL means never expires; otherwise $HOROLOG date of expiry
    Property ActiveUntil As %Integer;

}

