Class TestCatalogItemSearch Extends %RegisteredObject
{

    ClassMethod TestSearchItems()
    {
        Do ##class(Catalog.Item).%KillExtent()

        // Active item (no expiry)
        Set i1 = ##class(Catalog.Item).%New()
        Set i1.Name = "ActiveWidget"
        Set i1.Category = "Widgets"
        Set i1.ActiveUntil = ""
        Do i1.%Save()

        // Active item (expires far future)
        Set i2 = ##class(Catalog.Item).%New()
        Set i2.Name = "FutureWidget"
        Set i2.Category = "Widgets"
        Set i2.ActiveUntil = +$HOROLOG + 365
        Do i2.%Save()

        // Expired item
        Set i3 = ##class(Catalog.Item).%New()
        Set i3.Name = "ExpiredWidget"
        Set i3.Category = "Widgets"
        Set i3.ActiveUntil = +$HOROLOG - 1
        Do i3.%Save()

        Set results = ##class(Catalog.ItemSearch).SearchItems("Widgets")

        If (results.Count() '= 2) {
            Throw ##class(%Exception.General).%New("Expected 2 active items, got "_results.Count())
        }

        // Verify expired item not present
        For i=1:1:results.Count() {
            If (results.GetAt(i) = "ExpiredWidget") {
                Throw ##class(%Exception.General).%New("Expired item should not appear")
            }
        }
    }

}
